import React, { useEffect, useState } from 'react';
import axios from 'axios';

export default function MyPasses() {
  const [passes, setPasses] = useState([]);
  const [loading, setLoading] = useState(true);

  const load = () => {
    setLoading(true);
    axios.get('/api/pass/my').then(r => { setPasses(r.data); setLoading(false); });
  };

  useEffect(load, []);

  const renew = async (id) => {
    // For renewal, ideally we'd have a payment step, but for now we just post it
    await axios.post(`/api/pass/renew/${id}`, { passType: 'monthly', paymentStatus: 'completed' });
    load();
  };

  if (loading) return <div className="center-card-layout"><h2>Loading...</h2></div>;

  return (
    <div className="page-container animate-fade-in">
      <h1 className="page-title" style={{ textAlign: 'left', marginBottom: '32px' }}>🎫 My Bus Passes</h1>

      {passes.length === 0 && (
        <div style={{ textAlign: 'center', color: 'var(--text-light)', marginTop: 60 }}>
          No pass applications yet.<br />Go to "Apply Pass" to get started.
        </div>
      )}

      {passes.map(p => (
        <div key={p._id} className="glass-container" style={{ marginBottom: '16px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <div style={{ fontSize: 13, color: 'var(--text-light)', marginBottom: 4 }}>
              {p.passNumber ? `Pass #${p.passNumber}` : 'Pending Approval'}
            </div>
            <div style={{ fontSize: 18, fontWeight: 700, color: 'var(--text-dark)', marginBottom: 6 }}>
              {p.from} → {p.to}
            </div>
            <div style={{ fontSize: 13, color: 'var(--text-light)', display: 'flex', gap: 20, flexWrap: 'wrap' }}>
              <span>Type: <strong style={{ textTransform: 'capitalize' }}>{p.passType}</strong></span>
              <span>Applied: {new Date(p.appliedAt).toLocaleDateString()}</span>
              {p.validFrom && <span>Valid: {new Date(p.validFrom).toLocaleDateString()} – {new Date(p.validTo).toLocaleDateString()}</span>}
              {p.paymentStatus && <span>Payment: <strong style={{ color: p.paymentStatus === 'completed' ? 'var(--success)' : 'var(--warning)', textTransform: 'capitalize' }}>{p.paymentStatus}</strong></span>}
            </div>
            {p.remarks && p.status === 'rejected' && <div style={{ fontSize: 12, color: 'var(--danger)', marginTop: 4 }}>Reason: {p.remarks}</div>}
          </div>
          <div style={{ textAlign: 'right' }}>
            <div className={`badge badge-${p.status}`} style={{ display: 'inline-block', marginBottom: 8, fontSize: '0.85rem', padding: '6px 12px' }}>
              {p.status.toUpperCase()}
            </div>
            <br />
            {(p.status === 'approved' || p.status === 'expired') && (
              <button className="btn btn-outline btn-small" onClick={() => renew(p._id)}>Renew Pass</button>
            )}
          </div>
        </div>
      ))}
    </div>
  );
}
